import React, { createContext, useState, useContext } from 'react';
import axios from 'axios';
import toast from 'react-hot-toast';

const FarmContext = createContext();

export const useFarm = () => useContext(FarmContext);

const API_URL = 'http://localhost:8000/api';

export const FarmProvider = ({ children }) => {
  const [farm, setFarm] = useState(null);
  const [crops, setCrops] = useState([]);
  const [loading, setLoading] = useState(false);

  const registerFarm = async (farmData) => {
    setLoading(true);
    try {
      const response = await axios.post(`${API_URL}/farm/register`, farmData);
      toast.success(response.data.message);
      return response.data;
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Registration failed');
      return null;
    } finally {
      setLoading(false);
    }
  };

  const loginFarm = async (email, password) => {
    setLoading(true);
    try {
      const response = await axios.post(`${API_URL}/farm/login`, { email, password });
      if (response.data.success) {
        setFarm(response.data);
        localStorage.setItem('farm_session', JSON.stringify(response.data));
        toast.success(response.data.message);
        return response.data;
      }
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Login failed');
      return null;
    } finally {
      setLoading(false);
    }
  };

  const logout = () => {
    setFarm(null);
    localStorage.removeItem('farm_session');
    toast.success('Logged out successfully');
  };

  const loadFarmProfile = async (farmId) => {
    setLoading(true);
    try {
      const response = await axios.get(`${API_URL}/farm/${farmId}`);
      setFarm(prev => ({ ...prev, ...response.data }));
      return response.data;
    } catch (error) {
      toast.error('Failed to load farm profile');
      return null;
    } finally {
      setLoading(false);
    }
  };

  const loadCrops = async (farmId) => {
    setLoading(true);
    try {
      const response = await axios.get(`${API_URL}/crops/${farmId}`);
      setCrops(response.data.crops);
      return response.data.crops;
    } catch (error) {
      toast.error('Failed to load crops');
      return [];
    } finally {
      setLoading(false);
    }
  };

  const addCrop = async (cropData) => {
  setLoading(true);
  try {
    const response = await axios.post(`${API_URL}/crops`, cropData);
    if (response.data.success) {
      await loadCrops(cropData.farm_id);
      toast.success('Crop added successfully with AI analysis!');
      return response.data;
    }
  } catch (error) {
    toast.error(error.response?.data?.detail || 'Failed to add crop');
    return null;
  } finally {
    setLoading(false);
  }
};

  const updateFarmProfile = async (farmId, updates) => {
  setLoading(true);
  try {
    const response = await axios.put(`${API_URL}/farm/${farmId}`, updates);
    if (response.data.success) {
      setFarm(prev => ({ ...prev, ...updates }));
      toast.success('Profile updated successfully');
      return true;
    }
  } catch (error) {
    toast.error('Failed to update profile');
    return false;
  } finally {
    setLoading(false);
  }
};

  const updateCrop = async (cropId, updates) => {
    setLoading(true);
    try {
      const response = await axios.put(`${API_URL}/crops/${cropId}`, updates);
      if (response.data.success) {
        await loadCrops(farm?.farm_id);
        toast.success('Crop updated successfully');
        return response.data;
      }
    } catch (error) {
      toast.error('Failed to update crop');
      return null;
    } finally {
      setLoading(false);
    }
  };

  const deleteCrop = async (cropId) => {
    setLoading(true);
    try {
      const response = await axios.delete(`${API_URL}/crops/${cropId}`);
      if (response.data.success) {
        await loadCrops(farm?.farm_id);
        toast.success('Crop deleted successfully');
        return response.data;
      }
    } catch (error) {
      toast.error('Failed to delete crop');
      return null;
    } finally {
      setLoading(false);
    }
  };

  const analyzeCrop = async (cropId) => {
    setLoading(true);
    try {
      const response = await axios.get(`${API_URL}/crops/analyze/${cropId}`);
      return response.data;
    } catch (error) {
      toast.error('Failed to analyze crop');
      return null;
    } finally {
      setLoading(false);
    }
  };

  // Check for existing session on load
  React.useEffect(() => {
    const session = localStorage.getItem('farm_session');
    if (session) {
      const farmData = JSON.parse(session);
      setFarm(farmData);
      loadCrops(farmData.farm_id);
    }
  }, []);

  return (
    <FarmContext.Provider value={{
      farm,
      crops,
      loading,
      registerFarm,
      loginFarm,
      logout,
      loadFarmProfile,
      loadCrops,
      addCrop,
      updateCrop,
      deleteCrop,
      analyzeCrop,
      updateFarmProfile
    }}>
      {children}
    </FarmContext.Provider>
  );
};
